good-example.code-block:
import com.mongodb.client.MongoClient;
import com.mongodb.client.model.Filters;
import com.mongodb.client.model.Updates;
import io.mongock.api.annotations.ChangeUnit;
import io.mongock.api.annotations.Execution;
import io.mongock.api.annotations.RollbackExecution;

@ChangeUnit(id = "orders-add-status", order = "001", author = "platform")
public class OrdersAddStatusChange {

    @Execution
    public void execute(MongoClient mongoClient) {
        mongoClient.getDatabase("orders")
            .getCollection("orders")
            .updateMany(Filters.exists("status", false), Updates.set("status", "PENDING"));
    }

    @RollbackExecution
    public void rollback(MongoClient mongoClient) {
        mongoClient.getDatabase("orders")
            .getCollection("orders")
            .updateMany(Filters.eq("status", "PENDING"), Updates.unset("status"));
    }
}

bad-example.code-block:
// Bad: coupling migrations to Panache entity methods that may change later
@ChangeUnit(id = "orders-add-status", order = "001", author = "platform")
class OrdersAddStatusChange {
    @Execution
    void execute() {
        OrderEntity.listAll().forEach(order -> {
            order.status = "PENDING";
            order.update();
        });
    }
}

good-example.code-block:
import io.mongock.runner.core.executor.MongockRunner;
import io.quarkiverse.mongock.MongockFactory;
import jakarta.enterprise.context.ApplicationScoped;
import jakarta.inject.Inject;

@ApplicationScoped
public class MigrationService {

    @Inject MongockFactory mongockFactory;

    public void migrate() {
        MongockRunner runner = mongockFactory.createMongockRunner();
        runner.execute();
    }
}

bad-example.code-block:
// Bad: endpoint-triggered migration can race with normal traffic and repeated requests
@POST
@Path("/migrate")
public void migrateFromHttpRequest() {
    migrationService.migrate();
}

good-example.code-block:
@QuarkusTest
class MongockMigrationTest {

    @Inject MongoClient mongoClient;

    @Test
    void appliesOrderStatusMigration() {
        List<Document> orders = mongoClient.getDatabase("orders")
            .getCollection("orders")
            .find()
            .into(new ArrayList<>());

        assertThat(orders).allSatisfy(order -> assertThat(order).containsKey("status"));
    }
}
